-- Remaining services - Agriculture, Environment, Infrastructure, Taxation, Online Services, Office Pages
-- This covers the final 31 services to complete all 61

-- ===== AGRICULTURE (4 services) =====

UPDATE services SET description='Agricultural loans for farmers to support crop production, livestock raising, and farm development. Provides low-interest financing for agricultural activities.',fees='Varies (loan program)',processing_time='2-4 weeks',office='Municipal Agriculture Office',steps='[{"title":"Check Eligibility","description":"Must be: registered farmer, Ormoc City resident, with farmland (owned or leased), and good credit standing.","order":1},{"title":"Prepare Farm Plan","description":"Prepare simple farm plan: what to plant/raise, area, estimated costs, expected income. May need assistance from agricultural technician.","order":2},{"title":"Gather Requirements","description":"Bring: valid ID, proof of land ownership/lease, barangay certification as farmer, farm plan, and collateral documents if required.","order":3},{"title":"Submit Loan Application","description":"Go to Municipal Agriculture Office. Submit loan application with all requirements.","order":4},{"title":"Assessment and Approval","description":"Agricultural officer will assess your farm plan and eligibility. May conduct farm visit. Processing takes 2-4 weeks.","order":5},{"title":"Loan Release","description":"If approved, attend loan orientation. Sign loan documents. Loan released as cash or in-kind (seeds, fertilizer, etc.).","order":6},{"title":"Comply with Terms","description":"Use loan for intended purpose. Repay according to schedule. Maintain farm records for monitoring.","order":7}]'::jsonb,faq='[{"question":"How much can I borrow?","answer":"Loan amount varies based on farm size, crop/livestock type, and program. Typically ₱10,000-₱100,000. Larger amounts for organized farmer groups.","order":1},{"question":"What is the interest rate?","answer":"Agricultural loans typically have low interest (3-6% per annum) or zero interest for some programs. Much lower than commercial loans.","order":2},{"question":"Do I need collateral?","answer":"Depends on loan amount. Small loans may not require collateral. Larger loans may need land title, harvest assignment, or co-maker.","order":3},{"question":"Can I borrow if I am tenant farmer?","answer":"Yes, tenant farmers can borrow with landowner consent and lease agreement. Some programs specifically for tenant farmers.","order":4},{"question":"What if I cannot repay on time?","answer":"Contact Agriculture Office immediately. Restructuring or extension may be possible for valid reasons (crop failure, calamity). Do not default without communication.","order":5}]'::jsonb,office_details='{"name":"Municipal Agriculture Office","location":"City Hall","address":"Ormoc City, Leyte","phone":"+63 53 561 6000","hours":"Monday to Friday: 8:00 AM - 5:00 PM"}'::jsonb,requirements_by_type='{"individual_farmer":["Valid government-issued ID","Proof of land ownership (land title) or Lease contract","Barangay Certification as farmer","Farm plan with cost estimates","Collateral documents (if required)","Cedula"],"farmer_group":["Group registration documents","List of members with IDs","Proof of land ownership/lease of members","Group farm plan","Board resolution authorizing loan","Collateral documents (if required)"]}'::jsonb,related_services=ARRAY['fertilizer-assistance','crop-insurance'] WHERE slug='agricultural-loans';

UPDATE services SET description='Crop insurance program protecting farmers from losses due to natural calamities, pests, and diseases. Provides financial compensation for crop damage.',fees='Premium varies (subsidized)',processing_time='Before planting season',office='Philippine Crop Insurance Corporation (PCIC) or Municipal Agriculture Office',steps='[{"title":"Register as Farmer","description":"Register with PCIC or through Municipal Agriculture Office. Provide farm information and crop details.","order":1},{"title":"Choose Insurance Coverage","description":"Select crop type and coverage level. Premium varies based on crop, area, and coverage amount.","order":2},{"title":"Submit Application","description":"Submit insurance application before planting. Bring land title/lease, barangay certification, and valid ID.","order":3},{"title":"Pay Premium","description":"Pay insurance premium (partially subsidized by government). Keep official receipt.","order":4},{"title":"Plant Crop","description":"Plant insured crop within specified period. Follow recommended farming practices.","order":5},{"title":"Report Damage (if occurs)","description":"If crop damaged by calamity/pest, report to PCIC immediately. Do not harvest damaged crop yet.","order":6},{"title":"Claim Processing","description":"PCIC will assess damage. If valid claim, compensation will be processed and released.","order":7}]'::jsonb,faq='[{"question":"What crops are covered?","answer":"Rice, corn, and high-value crops. Coverage varies by season and area. Check with PCIC or Agriculture Office for current covered crops.","order":1},{"question":"How much is the premium?","answer":"Varies by crop and coverage. Government subsidizes 50-60% of premium. Farmer pays remaining 40-50%. Example: Rice insurance premium around ₱500-₱1,500 per hectare.","order":2},{"question":"What damages are covered?","answer":"Natural calamities (typhoon, flood, drought), pest infestation, and plant diseases. Not covered: poor farming practices, theft, fire caused by farmer.","order":3},{"question":"How much compensation can I get?","answer":"Based on coverage level chosen and extent of damage. Can be up to 100% of production cost or expected harvest value, depending on policy.","order":4},{"question":"Can I insure if I am tenant?","answer":"Yes, tenant farmers can get crop insurance with landowner consent. Some programs specifically for tenants.","order":5}]'::jsonb,office_details='{"name":"Philippine Crop Insurance Corporation (PCIC) / Municipal Agriculture Office","location":"PCIC Office or City Hall","address":"Ormoc City, Leyte","phone":"PCIC Hotline: 1-800-1-888-7422","hours":"Monday to Friday: 8:00 AM - 5:00 PM"}'::jsonb,requirements_by_type='{"crop_insurance":["Valid government-issued ID","Proof of land ownership (land title) or Lease contract","Barangay Certification as farmer","Sketch/map of farm location","Payment for premium"]}'::jsonb,related_services=ARRAY['agricultural-loans','fertilizer-assistance'] WHERE slug='crop-insurance';

UPDATE services SET description='Free or subsidized fertilizer assistance for farmers to improve crop productivity. Distributed during planting season to registered farmers.',fees='Free or subsidized',processing_time='During planting season',office='Municipal Agriculture Office',steps='[{"title":"Register as Farmer","description":"Register with Municipal Agriculture Office as active farmer. Provide farm information and crop plan.","order":1},{"title":"Check Distribution Schedule","description":"Monitor announcements for fertilizer distribution schedule. Usually before planting season.","order":2},{"title":"Prepare Requirements","description":"Bring valid ID, barangay certification as farmer, and proof of farmland (title or lease contract).","order":3},{"title":"Attend Distribution","description":"Go to designated distribution site on scheduled date. Arrive early as supply may be limited.","order":4},{"title":"Receive Fertilizer","description":"Receive allocated fertilizer (amount based on farm size). Sign acknowledgment receipt.","order":5},{"title":"Use Properly","description":"Use fertilizer for intended crop and follow recommended application. May be subject to monitoring.","order":6}]'::jsonb,faq='[{"question":"How much fertilizer can I get?","answer":"Allocation based on farm size, usually 1-2 bags per hectare. Total amount depends on program budget and number of beneficiaries.","order":1},{"question":"What type of fertilizer is given?","answer":"Usually complete fertilizer (14-14-14) or urea, depending on crop and season. Type determined by Agriculture Office based on soil and crop needs.","order":2},{"question":"Is it really free?","answer":"Yes, government-subsidized fertilizer is free or heavily discounted. However, supply is limited and distributed on first-come, first-served basis.","order":3},{"question":"Can I get fertilizer every season?","answer":"Depends on program and budget availability. Priority given to rice and corn farmers. Not guaranteed every season.","order":4},{"question":"What if I need more fertilizer?","answer":"Government assistance is limited. You may need to buy additional fertilizer from agricultural supply stores for full farm needs.","order":5}]'::jsonb,office_details='{"name":"Municipal Agriculture Office","location":"City Hall","address":"Ormoc City, Leyte","phone":"+63 53 561 6000","hours":"Monday to Friday: 8:00 AM - 5:00 PM"}'::jsonb,requirements_by_type='{"farmer":["Valid government-issued ID","Barangay Certification as farmer","Proof of land ownership or Lease contract","Farm sketch or location"]}'::jsonb,related_services=ARRAY['agricultural-loans','crop-insurance'] WHERE slug='fertilizer-assistance';

-- Municipal Agriculture Office (office page)
UPDATE services SET description='Municipal Agriculture Office provides agricultural extension services, training, loans, and assistance to farmers. Promotes agricultural development and food security.',fees='Varies by service',processing_time='Varies by service',office='Municipal Agriculture Office',steps='[{"title":"Visit Agriculture Office","description":"Located at City Hall. Consult with agricultural technicians for farming advice and assistance.","order":1},{"title":"Available Services","description":"Agricultural loans, fertilizer assistance, crop insurance, training programs, pest control, farm mechanization, and extension services.","order":2}]'::jsonb,faq='[{"question":"What services does Agriculture Office provide?","answer":"Agricultural loans, fertilizer/seed assistance, crop insurance facilitation, training, pest control advice, farm mechanization, and agricultural extension services.","order":1}]'::jsonb,office_details='{"name":"Municipal Agriculture Office","location":"City Hall","address":"Ormoc City, Leyte","phone":"+63 53 561 6000","hours":"Monday to Friday: 8:00 AM - 5:00 PM"}'::jsonb,requirements_by_type='{"general":["Valid ID for any transaction"]}'::jsonb,related_services=ARRAY['agricultural-loans','fertilizer-assistance','crop-insurance'] WHERE slug='municipal-agriculture-office';

-- ===== ENVIRONMENT (3 services) =====

UPDATE services SET description='Environmental Compliance Certificate (ECC) required for projects that may have environmental impact. Ensures compliance with environmental laws.',fees='Varies by project scale',processing_time='30-90 days',office='City Environment and Natural Resources Office (CENRO)',steps='[{"title":"Determine if ECC Required","description":"ECC required for: construction projects, industrial facilities, commercial establishments, and activities with potential environmental impact.","order":1},{"title":"Prepare Environmental Impact Assessment","description":"Hire environmental consultant to prepare EIA or Initial Environmental Examination (IEE) depending on project scale.","order":2},{"title":"Submit Application","description":"Submit ECC application with EIA/IEE, project description, and other requirements to CENRO.","order":3},{"title":"Public Consultation","description":"Conduct public consultation with affected communities if required for project type.","order":4},{"title":"CENRO Review","description":"CENRO will review EIA/IEE and conduct site inspection. May require additional information or mitigation measures.","order":5},{"title":"Approval and Issuance","description":"If compliant, ECC will be issued. Processing time: 30-90 days depending on project complexity.","order":6}]'::jsonb,faq='[{"question":"What projects need ECC?","answer":"Large construction, industrial facilities, mining, quarrying, waste facilities, and other environmentally critical projects. Small residential construction usually exempt.","order":1},{"question":"How much does ECC cost?","answer":"Fees vary by project scale and complexity. Includes application fee, EIA preparation (if consultant hired), and other processing fees.","order":2},{"question":"Can I start project without ECC?","answer":"No. Starting environmentally critical project without ECC is illegal and may result in stop-work order, fines, or criminal liability.","order":3}]'::jsonb,office_details='{"name":"City Environment and Natural Resources Office (CENRO)","location":"City Hall","address":"Ormoc City, Leyte","phone":"+63 53 561 6000","hours":"Monday to Friday: 8:00 AM - 5:00 PM"}'::jsonb,requirements_by_type='{"ecc_application":["Project description and location","Environmental Impact Assessment (EIA) or Initial Environmental Examination (IEE)","Land title or lease contract","Barangay clearance","Valid ID of project proponent","Payment for application fee"]}'::jsonb,related_services=ARRAY['building-permit','tree-cutting-permit'] WHERE slug='environmental-clearance';

UPDATE services SET description='Permit required to cut, prune, or remove trees. Protects trees and ensures proper tree management and replacement.',fees='₱100-₱500 per tree',processing_time='7-14 business days',office='City Environment and Natural Resources Office (CENRO)',steps='[{"title":"Assess Need to Cut Tree","description":"Determine if tree cutting is necessary (danger to property/life, construction, disease). Explore alternatives first.","order":1},{"title":"Prepare Justification","description":"Document reason for cutting: photos of tree condition, engineer certification if danger, building plan if for construction.","order":2},{"title":"Submit Application","description":"Go to CENRO. Submit tree cutting permit application with justification and requirements.","order":3},{"title":"Site Inspection","description":"CENRO will inspect tree and assess justification. May deny if tree is healthy and cutting not justified.","order":4},{"title":"Pay Fees and Replacement","description":"If approved, pay permit fee. May be required to plant replacement trees (usually 10 trees for every 1 cut).","order":5},{"title":"Receive Permit","description":"Get tree cutting permit. Cutting must be done within validity period (usually 30 days).","order":6},{"title":"Plant Replacement Trees","description":"Plant required number of replacement trees in designated area. Submit proof of planting to CENRO.","order":7}]'::jsonb,faq='[{"question":"Can I cut tree in my property without permit?","answer":"No. Even trees in private property require permit. Cutting without permit is illegal and punishable by law.","order":1},{"question":"How many replacement trees do I need to plant?","answer":"Usually 10 trees for every 1 tree cut. Exact number determined by CENRO based on tree size and species.","order":2},{"question":"What if tree is dangerous?","answer":"Emergency cutting may be allowed for immediate danger. Report to CENRO and barangay. Formal permit still needed after emergency cutting.","order":3}]'::jsonb,office_details='{"name":"City Environment and Natural Resources Office (CENRO)","location":"City Hall","address":"Ormoc City, Leyte","phone":"+63 53 561 6000","hours":"Monday to Friday: 8:00 AM - 5:00 PM"}'::jsonb,requirements_by_type='{"tree_cutting":["Valid government-issued ID","Proof of land ownership or authorization from owner","Photos of tree to be cut","Justification (engineer certification if danger, building plan if construction)","Barangay clearance","Payment for permit fee and replacement trees"]}'::jsonb,related_services=ARRAY['environmental-clearance','building-permit'] WHERE slug='tree-cutting-permit';

UPDATE services SET description='Waste collection, disposal, and management services. Includes garbage collection schedule, segregation guidelines, and special waste disposal.',fees='Included in real property tax',processing_time='Regular schedule',office='City Environment and Natural Resources Office (CENRO) / General Services Office',steps='[{"title":"Know Collection Schedule","description":"Check garbage collection schedule for your barangay. Usually 2-3 times per week. Follow schedule strictly.","order":1},{"title":"Segregate Waste","description":"Separate waste: biodegradable, non-biodegradable, recyclable, special waste. Use proper color-coded bags if required.","order":2},{"title":"Prepare for Collection","description":"Place segregated waste in designated area on collection day. Put out early morning before collection time.","order":3},{"title":"Special Waste Disposal","description":"For special waste (electronics, batteries, chemicals), bring to designated drop-off points or special collection events.","order":4},{"title":"Report Issues","description":"Report missed collection, illegal dumping, or waste management issues to barangay or CENRO.","order":5}]'::jsonb,faq='[{"question":"When is garbage collected in my area?","answer":"Collection schedule varies by barangay. Check with your barangay or CENRO for specific schedule. Usually 2-3 times per week.","order":1},{"question":"How should I segregate waste?","answer":"Biodegradable (food, garden waste), Non-biodegradable (plastic, styrofoam), Recyclable (paper, bottles, cans), Special waste (electronics, batteries, chemicals).","order":2},{"question":"What if garbage was not collected?","answer":"Report to barangay or call CENRO. Provide location and details. Keep waste secured until next collection.","order":3},{"question":"Where can I dispose special waste?","answer":"Electronics, batteries, chemicals should not go in regular garbage. Check with CENRO for drop-off points or special collection events.","order":4}]'::jsonb,office_details='{"name":"City Environment and Natural Resources Office (CENRO) / General Services Office","location":"City Hall","address":"Ormoc City, Leyte","phone":"+63 53 561 6000","hours":"Monday to Friday: 8:00 AM - 5:00 PM"}'::jsonb,requirements_by_type='{"regular_collection":["Follow collection schedule","Properly segregated waste"],"special_waste":["Bring to designated drop-off points","Follow handling guidelines"]}'::jsonb,related_services=ARRAY['environmental-clearance','barangay-clearance'] WHERE slug='waste-management-services';

